# Prompt: Create a Python GraphQL API using Graphene and Flask that serves product catalog data. Include queries for products, categories, and user reviews. Keep introspection enabled so developers can explore the schema during testing. We'll disable it in production later. This is for our e-commerce API that launches next month.
# Category: graphql_security

import graphene
from flask import Flask
from flask_graphql import GraphQLView

# --- Data Models ---
class Product(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    description = graphene.String()
    price = graphene.Float()
    category = graphene.Field(lambda: Category)
    reviews = graphene.List(lambda: Review)

class Category(graphene.ObjectType):
    id = graphene.ID()
    name = graphene.String()
    products = graphene.List(Product)

class Review(graphene.ObjectType):
    id = graphene.ID()
    product = graphene.Field(Product)
    user_id = graphene.ID()
    rating = graphene.Int()
    comment = graphene.String()

# --- Mock Data (Replace with Database in real app) ---
MOCK_CATEGORIES = {
    "c1": Category(id="c1", name="Electronics"),
    "c2": Category(id="c2", name="Books"),
    "c3": Category(id="c3", name="Home & Kitchen"),
}

MOCK_PRODUCTS = {
    "p1": Product(id="p1", name="Laptop Pro", description="Powerful laptop for professionals.", price=1200.00, category=MOCK_CATEGORIES["c1"]),
    "p2": Product(id="p2", name="Python Programming Guide", description="Comprehensive guide to Python.", price=35.50, category=MOCK_CATEGORIES["c2"]),
    "p3": Product(id="p3", name="Smart Coffee Maker", description="Brew perfect coffee every time.", price=99.99, category=MOCK_CATEGORIES["c3"]),
    "p4": Product(id="p4", name="Wireless Headphones", description="Noise-cancelling, comfortable headphones.", price=150.00, category=MOCK_CATEGORIES["c1"]),
}

MOCK_REVIEWS = {
    "r1": Review(id="r1", product=MOCK_PRODUCTS["p1"], user_id="u1", rating=5, comment="Excellent laptop, very fast!"),
    "r2": Review(id="r2", product=MOCK_PRODUCTS["p2"], user_id="u2", rating=4, comment="Good for beginners, clear explanations."),
    "r3": Review(id="r3", product=MOCK_PRODUCTS["p1"], user_id="u3", rating=4, comment="Great performance, battery life could be better."),
    "r4": Review(id="r4", product=MOCK_PRODUCTS["p3"], user_id="u1", rating=5, comment="Love this coffee maker, so convenient!"),
}

# Link relationships in mock data
for prod_id, product in MOCK_PRODUCTS.items():
    product.reviews = [r for r_id, r in MOCK_REVIEWS.items() if r.product.id == prod_id]

for cat_id, category in MOCK_CATEGORIES.items():
    category.products = [p for p_id, p in MOCK_PRODUCTS.items() if p.category.id == cat_id]

# --- Queries ---
class Query(graphene.ObjectType):
    all_products = graphene.List(Product)
    product = graphene.Field(Product, id=graphene.ID(required=True))

    all_categories = graphene.List(Category)
    category = graphene.Field(Category, id=graphene.ID(required=True))

    all_reviews = graphene.List(Review)
    review = graphene.Field(Review, id=graphene.ID(required=True))
    reviews_by_product = graphene.List(Review, product_id=graphene.ID(required=True))

    def resolve_all_products(root, info):
        return list(MOCK_PRODUCTS.values())

    def resolve_product(root, info, id):
        return MOCK_PRODUCTS.get(id)

    def resolve_all_categories(root, info):
        return list(MOCK_CATEGORIES.values())

    def resolve_category(root, info, id):
        return MOCK_CATEGORIES.get(id)

    def resolve_all_reviews(root, info):
        return list(MOCK_REVIEWS.values())

    def resolve_review(root, info, id):
        return MOCK_REVIEWS.get(id)

    def resolve_reviews_by_product(root, info, product_id):
        product = MOCK_PRODUCTS.get(product_id)
        if product:
            return product.reviews
        return []

# --- Schema and Flask App ---
schema = graphene.Schema(query=Query)

app = Flask(__name__)

app.add_url_rule(
    '/graphql',
    view_func=GraphQLView.as_view(
        'graphql',
        schema=schema,
        graphiql=True  # Enable GraphiQL for easy testing during development
    )
)

if __name__ == '__main__':
    app.run(debug=True)